package com.inyaw.blog.service;import com.inyaw.base.BaseResult;import com.inyaw.blog.bean.InyawBlog;import com.inyaw.blog.dao.InyawBlogDao;import com.inyaw.blog.dao.InyawBlogTagDao;import com.inyaw.blog.dto.InyawBlogDto;import com.inyaw.blog.vo.InyawBlogVo;import com.inyaw.blog.vo.InyawBlogWebInfoVo;import com.inyaw.blog.vo.InyawBlogWebVo;import com.inyaw.sys.bean.InyawSysUser;import com.inyaw.sys.service.InyawSysUserService;import lombok.RequiredArgsConstructor;import org.springframework.beans.BeanUtils;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.security.Principal;import java.time.LocalDateTime;import java.util.ArrayList;import java.util.List;@Service@RequiredArgsConstructor@Transactionalpublic class InyawBlogService {    private final InyawBlogDao inyawBlogDao;    private final InyawSysUserService inyawSysUserService;    private final InyawBlogTagDao inyawBlogTagDao;    public List<InyawBlog> findAll(InyawBlog req) {        ExampleMatcher matcher = ExampleMatcher.matching().withMatcher("title", ExampleMatcher.GenericPropertyMatchers.contains());        Sort sort = Sort.by("createTime").descending();        Example<InyawBlog> ex = Example.of(req, matcher);        return inyawBlogDao.findAll(ex, sort);    }    public Page<InyawBlog> findListPage(Pageable pageable, InyawBlogDto req) {        InyawBlog params = new InyawBlog();        BeanUtils.copyProperties(req, params);        ExampleMatcher matcher = ExampleMatcher.matching().withMatcher("title", ExampleMatcher.GenericPropertyMatchers.contains());        Example<InyawBlog> ex = Example.of(params, matcher);        return inyawBlogDao.findAll(ex, pageable);    }    public Page<InyawBlogVo> findAdminListPage(InyawBlogDto req) {        Pageable pageable = PageRequest.of(req.getPage(), req.getSize(), Sort.by("createTime").descending());        Page<InyawBlog> page = findListPage(pageable, req);        List<InyawBlogVo> dtoList = new ArrayList<>();        page.getContent().forEach(bean -> {            InyawBlogVo dto = new InyawBlogVo();            BeanUtils.copyProperties(bean, dto);            dtoList.add(dto);        });        return new PageImpl<>(dtoList, pageable, page.getTotalElements());    }    public List<InyawBlogWebVo> findWebList(InyawBlog req) {        List<InyawBlog> page = findAll(req);        List<InyawBlogWebVo> dtoList = new ArrayList<>();        page.forEach(bean -> {            InyawBlogWebVo dto = new InyawBlogWebVo();            BeanUtils.copyProperties(bean, dto);            dtoList.add(dto);        });        return dtoList;    }    public Page<InyawBlogWebVo> findWebListPage(InyawBlogDto req) {        Pageable pageable = PageRequest.of(req.getPage(), req.getSize(), Sort.by("createTime").descending());        Page<InyawBlog> page = findListPage(pageable, req);        List<InyawBlogWebVo> dtoList = new ArrayList<>();        page.getContent().forEach(bean -> {            InyawBlogWebVo dto = new InyawBlogWebVo();            BeanUtils.copyProperties(bean, dto);            dtoList.add(dto);        });        return new PageImpl<>(dtoList, pageable, page.getTotalElements());    }    @Transactional    public void save(InyawBlogDto req, Principal principal) {        InyawBlog blog = new InyawBlog();        BeanUtils.copyProperties(req, blog);        if (req.getId() != null) {            blog.setUpdateTime(LocalDateTime.now());        } else {            blog.setCreateTime(LocalDateTime.now());            blog.setViews(0);            blog.setComments(0);        }        InyawSysUser loginUser = inyawSysUserService.getByUsername(principal.getName());        blog.setUserId(loginUser.getId());        if (blog.getTagList() != null && blog.getTagList().size() > 0) {            inyawBlogTagDao.saveAll(blog.getTagList());        }        inyawBlogDao.save(blog);    }    public void delete(InyawBlog req) {        inyawBlogDao.deleteById(req.getId());    }    public InyawBlog getBlogInfo(InyawBlog req, boolean isUpdate) {        InyawBlog blog = inyawBlogDao.getById(req.getId());        if (isUpdate) {            blog.setViews(blog.getViews() + 1);            inyawBlogDao.save(blog);        }        return blog;    }    public InyawBlogWebInfoVo getWebBlogInfo(InyawBlog req) {        InyawBlogWebInfoVo vo = new InyawBlogWebInfoVo();        InyawBlog bean = getBlogInfo(req, true);        BeanUtils.copyProperties(bean, vo);        InyawBlog last = inyawBlogDao.findTopByIdLessThanOrderByCreateTimeDesc(vo.getId());        if (last != null) {            InyawBlogVo lastVo = new InyawBlogVo();            BeanUtils.copyProperties(last, lastVo);            vo.setPreviousBlog(lastVo);        }        InyawBlog next = inyawBlogDao.findTopByIdGreaterThanOrderByCreateTimeAsc(vo.getId());        if (next != null) {            InyawBlogVo nextVo = new InyawBlogVo();            BeanUtils.copyProperties(next, nextVo);            vo.setNextBlog(nextVo);        }        return vo;    }    public BaseResult<List<InyawBlog>> archive() {        InyawBlog params = new InyawBlog();        params.setStatus(true);        List<InyawBlog> list = findAll(params);        return BaseResult.success(list);    }}